Code.Terraform:
```hcl
# 2つのオリジンでオリジングループを設定し、デフォルトキャッシュ動作で使用
resource "aws_cloudfront_distribution" "<example_resource_name>" {
  enabled = true

  origin {
    domain_name = "<primary_origin_domain>"
    origin_id   = "primary"
    s3_origin_config {}
  }

  origin {
    domain_name = "<secondary_origin_domain>"
    origin_id   = "secondary"
    s3_origin_config {}
  }

  origin_group {
    origin_id = "<example_origin_group_id>"  # 重要：2つのオリジンでオリジングループを定義
    failover_criteria {
      status_codes = [500]  # 重要：500でフェイルオーバーしてオリジンフェイルオーバーを有効化
    }
    member { origin_id = "primary" }
    member { origin_id = "secondary" }
  }

  default_cache_behavior {
    target_origin_id       = "<example_origin_group_id>"  # 重要：リクエストにオリジングループを使用
    viewer_protocol_policy = "allow-all"
    forwarded_values {
      query_string = false
      cookies { forward = "none" }
    }
  }

  restrictions {
    geo_restriction { restriction_type = "none" }
  }

  viewer_certificate { cloudfront_default_certificate = true }
}
```
